import { Helmet } from "react-helmet-async";
import { Link, useRoute } from "wouter";
import { ArrowLeft, ArrowRight, CalendarDays, Clock, User } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import StaticPageMotion from "@/components/StaticPageMotion";
import AdPlaceholder from "@/components/AdPlaceholder";
import { getBlogPost, getPublishedBlogPosts } from "@/data/blogPosts";
import { SITE_URL } from "@/data/siteRoutes";

export default function BlogPost() {
  const [, params] = useRoute<{ slug: string }>("/blog/:slug");
  const post = getBlogPost(params?.slug);
  const publishedPosts = getPublishedBlogPosts();

  if (!post) {
    return (
      <main className="mx-auto max-w-3xl px-4 py-16 text-center sm:px-6">
        <SEOHead
          title="Blog Post Not Found | CalcHive"
          description="The CalcHive blog article you are looking for could not be found."
          canonical="/blog"
          category="company"
          breadcrumbName="Blog"
        />
        <StaticPageMotion />
        <h1 className="text-3xl font-extrabold text-foreground">Blog post not found</h1>
        <p className="mt-3 text-muted-foreground">The article may have moved or the URL may be incorrect.</p>
        <Link href="/blog" className="mt-6 inline-flex items-center gap-2 rounded-xl bg-primary px-5 py-3 text-sm font-bold text-primary-foreground">
          <ArrowLeft className="h-4 w-4" /> Back to Blog
        </Link>
      </main>
    );
  }

  const canonical = `/blog/${post.slug}`;
  const absoluteUrl = `${SITE_URL}${canonical}`;
  const publishedAt = post.publishDate ?? post.date;
  const imageUrl = post.featuredImage ? `${SITE_URL}${post.featuredImage}` : `${SITE_URL}/opengraph.jpg`;
  const articleSchema = {
    "@context": "https://schema.org",
    "@type": "Article",
    "headline": post.title,
    "description": post.description,
    "datePublished": publishedAt,
    "dateModified": publishedAt,
    "image": imageUrl,
    "author": { "@type": "Organization", "name": post.author },
    "publisher": {
      "@type": "Organization",
      "name": "CalcHive",
      "logo": { "@type": "ImageObject", "url": `${SITE_URL}/logo-192.png` },
    },
    "mainEntityOfPage": absoluteUrl,
  };

  return (
    <>
      <SEOHead
        title={post.seoTitle}
        description={post.description}
        canonical={canonical}
        category="company"
        breadcrumbName={post.title}
      />
      <Helmet>
        <meta property="og:type" content="article" />
        <meta property="article:published_time" content={publishedAt} />
        <meta property="article:author" content={post.author} />
        <meta property="article:section" content={post.category} />
        <script type="application/ld+json">{JSON.stringify(articleSchema)}</script>
      </Helmet>
      <StaticPageMotion />

      <main className="calchive-static-motion bg-background">
        <article className="mx-auto max-w-3xl px-4 py-8 sm:px-6 sm:py-12">
          <Link href="/blog" className="mb-7 inline-flex items-center gap-2 text-sm font-bold text-primary hover:underline">
            <ArrowLeft className="h-4 w-4" /> Back to Blog
          </Link>

          <header className="border-b border-border pb-7">
            <div className="mb-4 flex flex-wrap items-center gap-2 text-xs font-semibold text-muted-foreground">
              <span className="rounded-full border border-border bg-card px-2.5 py-1 uppercase tracking-wide">{post.category}</span>
              <span className="inline-flex items-center gap-1"><CalendarDays className="h-3.5 w-3.5" /> {new Date(post.date).toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" })}</span>
              <span className="inline-flex items-center gap-1"><Clock className="h-3.5 w-3.5" /> {post.readTime}</span>
              <span className="inline-flex items-center gap-1"><User className="h-3.5 w-3.5" /> {post.author}</span>
            </div>
            <h1 className="text-3xl font-extrabold leading-tight tracking-tight text-foreground sm:text-5xl">
              {post.title}
            </h1>
            <p className="mt-4 text-base leading-relaxed text-muted-foreground sm:text-lg">
              {post.description}
            </p>
          </header>

          <AdPlaceholder size="banner" className="mt-8" />

          <div className="mt-8 space-y-10">
            {post.sections.map((section) => (
              <section key={section.heading}>
                <h2 className="text-2xl font-extrabold tracking-tight text-foreground">{section.heading}</h2>
                {section.subheading && <h3 className="mt-4 text-lg font-bold text-foreground">{section.subheading}</h3>}
                {section.paragraphs.map((paragraph) => (
                  <p key={paragraph} className="mt-4 text-base leading-8 text-muted-foreground">{paragraph}</p>
                ))}
              </section>
            ))}
          </div>

          <AdPlaceholder size="rectangle" className="mx-auto mt-12" />

          <section className="mt-12 rounded-2xl border border-border bg-card p-5 sm:p-6">
            <h2 className="text-xl font-extrabold text-foreground">Related calculators</h2>
            <div className="mt-4 grid gap-3">
              {post.relatedCalculators.map((calculator) => (
                <Link
                  key={calculator.href}
                  href={calculator.href}
                  className="group flex items-center justify-between gap-4 rounded-xl border border-border bg-background p-4 transition-all hover:border-primary/40 hover:shadow-sm"
                >
                  <div>
                    <h3 className="text-sm font-bold text-foreground group-hover:text-primary">{calculator.title}</h3>
                    <p className="mt-1 text-xs leading-relaxed text-muted-foreground">{calculator.description}</p>
                  </div>
                  <ArrowRight className="h-4 w-4 flex-shrink-0 text-muted-foreground transition-transform group-hover:translate-x-0.5 group-hover:text-primary" />
                </Link>
              ))}
            </div>
          </section>

          <AdPlaceholder size="banner" className="mt-8" />

          <nav className="mt-8 flex flex-wrap gap-3">
            {publishedPosts
              .filter((candidate) => candidate.slug !== post.slug)
              .slice(0, 2)
              .map((candidate) => (
                <Link key={candidate.slug} href={`/blog/${candidate.slug}`} className="rounded-full border border-border bg-card px-4 py-2 text-xs font-bold text-muted-foreground transition-colors hover:border-primary/40 hover:text-foreground">
                  {candidate.title}
                </Link>
              ))}
          </nav>
        </article>
      </main>
    </>
  );
}
